  "Excision of penile Paraffinoma.faq.0.a": {
    "title": "ผลลัพธ์ขึ้นอยู่กับความรุนแรงของความเสียหายที่มีอยู่เดิมครับ ศัลยแพทย์ของเราจะมุ่งเน้นกู้คืนทั้งรูปลักษณ์และการใช้งานให้ได้มากที่สุด แต่ในกรณีที่เนื้อเยื่อเสียหายรุนแรง อาจไม่สามารถกลับมาเป็นปกติ 100% ได้ การเข้ารับการรักษาเร็วมักให้ผลลัพธ์ที่ดีกว่าครับ"
  },
  "Excision of penile Paraffinoma.faq.1.q": {
    "title": "จะมีผลต่อการแข็งตัวหรือสมรรถภาพทางเพศไหม?"
  },
  "Excision of penile Paraffinoma.faq.1.a": {
    "title": "การฟื้นตัวของสมรรถภาพขึ้นอยู่กับระดับความเสียหายของเส้นประสาทและเนื้อเยื่อที่เกิดจากสารแปลกปลอม ศัลยแพทย์จะให้ความสำคัญเป็นอันดับแรกในการรักษาสมรรถภาพการแข็งตัวไว้ แต่ในกรณีที่ความเสียหายรุนแรง อาจมีผลกระทบบ้างครับ"
  },
  "Excision of penile Paraffinoma.faq.2.q": {
    "title": "ถ้าปล่อยไว้ไม่รักษา จะเสี่ยงเป็นมะเร็งไหม?"
  },
  "Excision of penile Paraffinoma.faq.2.a": {
    "title": "การอักเสบเรื้อรังจากปฏิกิริยาต่อต้านสารแปลกปลอมสามารถเพิ่มความเสี่ยงต่อการกลายพันธุ์ของเซลล์ได้เมื่อเวลาผ่านไป นี่เป็นหนึ่งในเหตุผลที่แนะนำให้ผ่าตัดนำสารออกโดยเร็ว เพื่อป้องกันทั้งการทำลายเนื้อเยื่อที่ลุกลามและความเสี่ยงมะเร็งในระยะยาวครับ"
  },
  "Vasectomy.title": {
    "title": "ทำหมันชายไร้ใบมีด (No-Scalpel Vasectomy)"
  },
  "Vasectomy.tagline": {
    "title": "ทำหมันชายไร้ใบมีด วิธีคุมกำเนิดถาวรที่ปลอดภัยและมีประสิทธิภาพสูงสุดสำหรับผู้ชาย ทำเร็ว ไม่มีผลต่อสมรรถภาพทางเพศ"
  },
  "Vasectomy.whatIsIt.title": {
    "title": "การทำหมันชายไร้ใบมีด (No-Scalpel Vasectomy) คืออะไร?"
  },
  "Vasectomy.whatIsIt.description": {
    "title": "การทำหมันชายไร้ใบมีดเป็นเทคนิคสมัยใหม่ที่รบกวนร่างกายน้อยที่สุดเพื่อคุมกำเนิดแบบถาวร แพทย์จะใช้เครื่องมือเฉพาะทางเจาะช่องเล็กๆ (3-5 มม.) ที่ผิวหนังถุงอัณฑะแทนการกรีดแผลแบบเดิม จากนั้นจะตัดและผูกท่อนำอสุจิ (Vas Deferens) เพื่อป้องกันไม่ให้ตัวอสุจิผสมกับน้ำอสุจิอย่างถาวร หัตถการใช้เวลาเพียง 15-20 นาทีภายใต้ยาชาเฉพาะที่ และกลับบ้านได้ในวันเดียว สมรรถภาพทางเพศ ระดับฮอร์โมน และการหลั่งยังคงเป็นปกติไม่เปลี่ยนแปลง"
  },
  "Vasectomy.description": {
    "title": "การทำหมันชายเป็นหัตถการผู้ป่วยนอกที่ให้ผลคุมกำเนิดแบบถาวร โดยการปิดกั้นท่อนำอสุจิ (Vas Deferens) ซึ่งเป็นท่อลำเลียงตัวอสุจิจากลูกอัณฑะไปยังน้ำอสุจิ เป็นวิธีคุมกำเนิดที่ได้รับการยอมรับทั่วโลกว่ามีประสิทธิภาพสูงที่สุด (มากกว่า 99.9%) ใช้เพียงยาชาเฉพาะที่ และที่สำคัญที่สุดคือ **ไม่มีผลกระทบใดๆ ต่อระดับฮอร์โมนเทสโทสเตอโรน ความต้องการทางเพศ การแข็งตัว หรือการหลั่ง** ปริมาณน้ำอสุจิยังคงเท่าเดิม เพียงแต่จะไม่มีตัวอสุจิอยู่ในนั้นเท่านั้น"
  },
